(55, 'AFRONATION Portugal Premium 2026', 'afronation-portugal-premium-2026-copy', NULL, 'AFRONATION Portugal Premium 2026 is a curated NBGS Travel group departure centered around Lisbon & Algarve, Portugal. Highlights include 2-Nights 4★ Accommodation in Lisbon, 4-Nights 4★ Accommodation in Portimao (3 Minutes from Festival), 1-Night 4★ Accommodation in Lisbon. Travel window: 30 JUNE - 07 JULY 2026.', 'AFRONATION Portugal Premium 2026 is a curated NBGS Travel package for Lisbon & Algarve, Portugal. Pricing is per person sharing. Travel details: 30 JUNE - 07 JULY 2026. Package highlights include 2-Nights 4★ Accommodation in Lisbon, 4-Nights 4★ Accommodation in Portimao (3 Minutes from Festival), 1-Night 4★ Accommodation in Lisbon, Return flights from Johannesburg to Lisbon, Return airport transfers. ONLY 1 Spot Remains for Female SOLO Traveler A R3000 non-refundable deposit is required to secure your booking. Travel dates are fixed for 30 June – 07 July 2026. Prices are per person sharing.', 'Europe', 'Portugal', 'Lisbon', 'Lisbon & Algarve', 'Lisbon & Algarve', 'group_trip', 'Group Trip', '7 Nights / 8 Days', '50000.00', 'ZAR', 'per_person_sharing', 'From', '5000.00', 1, '2026-06-30', '2026-07-07', 1, 'published', 0, NULL, NULL, NULL, NULL, '{"bio":"AFRONATION Portugal Premium 2026 is a curated NBGS Travel group departure centered around Lisbon & Algarve, Portugal. Highlights include 2-Nights 4★ Accommodation in Lisbon, 4-Nights 4★ Accommodation in Portimao (3 Minutes from Festival), 1-Night 4★ Accommodation in Lisbon. Travel window: 30 JUNE - 07 JULY 2026.","nights":7,"gallery":["/uploads/imported/live-packages/afronation-portugal-premium-2026-copy/00-mejores-fiestas-ibiza-2022.jpeg"],"excludes":["Afronation festival ticket","Transfers from hotel to festival","Meals not specified","Schengen Visa fee (visa assistance provided)","Tourism tax of €2-4 per night","Travel and medical insurance","Personal items and optional activities"],"includes":["2-Nights 4★ Accommodation in Lisbon","4-Nights 4★ Accommodation in Portimao (3 Minutes from Festival)","1-Night 4★ Accommodation in Lisbon","Return flights from Johannesburg to Lisbon","Return airport transfers","Return domestic transfers","Breakfast daily","Lisbon Pub crawl including drinks","Lisbon city tour","Benagil caves cruise","Visa assistance"],"dateOfTrip":"2026-06-30","tripPolicy":"ONLY 1 Spot Remains for Female SOLO Traveler\\nA R3000 non-refundable deposit is required to secure your booking.\\nTravel dates are fixed for 30 June – 07 July 2026.\\nPrices are per person sharing.\\nTo upgrade to a single room will be R20 000.00.\\nVisa assistance is provided, but the Schengen visa fee is not included.\\nTravel insurance is recommended and must be purchased separately.\\nThis package does not include the Afronation ticket.\\nExtensions to other European countries can be arranged on request.\\nTERMS AND CONDITIONS\\nAll prices are indicative and correct at time of loading onto the NBGS Travel website and are subject to change due to currency fluctuations, rate increases, airfare increases and availability. Please view more information on our terms and conditions on the “NBGS Booking form and terms& conditions”.\\nConfirmation & payment:\\nConfirmation is subject to payment and payment must be cleared in full before arrival.\\nFull payment is required to go on the trip.\\nFull payment must be paid by 30 April 2026.\\nInstalment plan can be as stipulated below or R5000 x 8 months or according your preferences.\\nPlease note 50% deposit is required by 1 February in order to begin Visa process & flights otherwise there is risk of price increase.\\nInstalment Plan:\\nR3000.00 Non-refundable Deposit\\nR3000.00 30 September 2025\\nR4000.00 31 October 2025\\nR5000.00 28 November 2025\\nR5000.00 26 December 2025\\nR5000.00 30 January 2026\\nR5000.00 28 February 2026\\nR5000.00 31 March 2026\\nR5000.00 30 April 2026","youtubeUrl":null,"isLocalTrip":false,"describeTrip":"AFRONATION Portugal Premium 2026 is a curated NBGS Travel package for Lisbon & Algarve, Portugal. Pricing is per person sharing. Travel details: 30 JUNE - 07 JULY 2026. Package highlights include 2-Nights 4★ Accommodation in Lisbon, 4-Nights 4★ Accommodation in Portimao (3 Minutes from Festival), 1-Night 4★ Accommodation in Lisbon, Return flights from Johannesburg to Lisbon, Return airport transfers. ONLY 1 Spot Remains for Female SOLO Traveler A R3000 non-refundable deposit is required to secure your booking. Travel dates are fixed for 30 June – 07 July 2026. Prices are per person sharing.","mainTripType":"Group Trip","travelDateLabel":"30 JUNE - 07 JULY 2026","backgroundListingImage":"/uploads/imported/live-packages/afronation-portugal-premium-2026-copy/00-mejores-fiestas-ibiza-2022.jpeg"}', '2026-04-13 02:26:19', '2026-04-13 02:34:54'),
(56, 'Snow in Poland & Czech 2026', 'snow-in-poland-czech-2026', NULL, 'Snow in Poland & Czech 2026 is a curated NBGS Travel travel package centered around Warsaw & Prague, Poland. Highlights include Return flights from Johannesburg to Czech & Poland, 3 Nights Accommodation in Prague, 2 Nights Accommodation in Zakopane. Travel window: January | February | March.', 'Snow in Poland & Czech 2026 is a curated NBGS Travel package for Warsaw & Prague, Poland. Pricing is per person sharing. Travel details: January | February | March. Package highlights include Return flights from Johannesburg to Czech & Poland, 3 Nights Accommodation in Prague, 2 Nights Accommodation in Zakopane, 2 Nights Accommodation in Warsaw, Return airport transfers. This package is valid for travel between January | February | March 2026. Travelers may choose their own preferred dates within this period. Surcharge applies for solo travelers. A non-refundable deposit of R5000 is required to secure your spot. Flexible installment payment options available. Travel must be booked in advance, subject to availability. TERMS AND CONDITIONS All prices are indicative and correct at time of loading onto the NBGS Travel website and are subject to change due to currency fluctuations, rate increases, airfare increases and availability.', 'Europe', 'Poland', '', 'Warsaw & Prague', 'Warsaw & Prague', 'package', 'Travel Package', '7 Nights / 8 Days', '43000.00', 'ZAR', 'per_person_sharing', 'From', '5000.00', 0, NULL, NULL, 1, 'published', 0, NULL, NULL, NULL, NULL, '{"bio":"Snow in Poland & Czech 2026 is a curated NBGS Travel travel package centered around Warsaw & Prague, Poland. Highlights include Return flights from Johannesburg to Czech & Poland, 3 Nights Accommodation in Prague, 2 Nights Accommodation in Zakopane. Travel window: January | February | March.","nights":7,"gallery":["/uploads/imported/live-packages/snow-in-poland-czech-2026/01-photo-1584992162608-ed1d62939d41-1024x768.avif","/uploads/imported/live